import{_ as e,o as a,c as t,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"艾克列尔圣辉盾","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/艾克列尔圣辉盾 .md","filePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/艾克列尔圣辉盾 .md"}'),s={name:"4.资源分区/7.物品与装备/3.防具/7.可升级/艾克列尔圣辉盾 .md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"艾克列尔圣辉盾",tabindex:"-1"},[n("艾克列尔圣辉盾 "),r("a",{class:"header-anchor",href:"#艾克列尔圣辉盾","aria-label":'Permalink to "艾克列尔圣辉盾"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),p('<h1 id="艾克列尔圣辉盾-1" tabindex="-1">艾克列尔圣辉盾 <a class="header-anchor" href="#艾克列尔圣辉盾-1" aria-label="Permalink to &quot;艾克列尔圣辉盾&quot;">​</a></h1><p>艾克列尔圣辉盾<br> 魔幻本质<br> 本武器为逐级升级。<br> 描述：由艾克列尔圣骑士团铸造的制式圣盾，也是代表着圣骑士团希望的圣物，象征着守护世界的誓约与无畏牺牲的英勇意志。<br> 特殊的，在购买了本武器后，你不能再购买四柱之枪-救世主或其变体资源。<br> 本武器的效果逐级替换。</p><p>艾克列尔圣辉盾<br> 价格：D+1000<br> 分类：轻盾<br> 武器伤害：4L<br> 特性：【格挡6】<br> 体积：2<br> 专业：盾<br> 伤害类型：物理-钝击<br> 描述： 盾身由精铁铸造，盾面錾刻着持盾者的姓名与圣辉纹章，中心镶嵌着一枚由经过神言祝福过的圣晶核心。<br> “世界的神明突然消失了，邪神出现了，世界各地开始出现天灾，并且涌现出了邪神的军队！”<br> “翼之纹章是自由的证明，吾等乃艾克列尔圣骑士团…… 与绝望抗争之人。”——「圣骑士团战纪：起始之章」<br> 效果：【圣辉共鸣】：你无畏的信念与圣辉盾产生深度共鸣，这份源自守护苍生的纯粹信仰会转化为温润且坚韧的圣辉能量持续注入到盾心的圣晶核心中。当你使用此盾牌进行格挡时，因此格挡产生的【格挡防御】替换为【能量防御】。<br> 【守护与牺牲】：盾中的圣辉纹章承载着艾克列尔圣骑士团以血践行守护誓约的信仰，前人未消散的守护信仰与牺牲意志会化作炽热的圣能涌入盾牌守护活在当下的人。当你在场景内首次因能量防御抵消了5点伤害值后，此盾牌立刻获得额外的【格挡3】特性，并且使用本盾牌攻击时，额外获得1点增强加值，持续一场景。</p><p>艾克列尔圣辉盾<br> 价格：C+1000<br> 分类：轻盾<br> 武器伤害：8L<br> 特性：【格挡10】<br> 体积：8<br> 力量需求：2<br> 专业：盾<br> 伤害类型：物理-钝击<br> 描述： 盾身由精铁铸造，盾面錾刻着原持盾者的姓名与圣辉纹章，中心镶嵌着一枚由经过神言祝福过的圣晶核心。<br> “打倒统御海洋的使者，夺回了这片美丽的海洋。总觉得，好像已经很久没有见过大家露出这样的笑容了。”<br> “讨伐统御大地的使者，夺回了这片丰饶的大地。…… 真想让逝去的同胞们，也看一看这般景象。”<br> “成功击败统御天空的使者，收复了天空。…… 牺牲人数：■■■（字迹被打湿，模糊不清了）。”——「圣骑士团团长日记：节选」<br> 效果：【圣辉共鸣】：你无畏的信念与圣辉盾产生深度共鸣，这份源自守护苍生的纯粹信仰会转化为温润且坚韧的圣辉能量持续注入到盾心的圣晶核心中。当你使用此盾牌进行格挡时，因此格挡产生的【格挡防御】替换为【能量防御】。<br> 【守护与牺牲】：盾中的圣辉纹章承载着艾克列尔圣骑士团以血践行守护誓约的信仰，前人未消散的守护信仰与牺牲意志会化作炽热的圣能涌入盾牌守护活在当下的人。当你在场景内首次因能量防御抵消了5点伤害值后，此盾牌立刻获得额外的【格挡3】特性，并且使用本盾牌攻击时，额外获得1点增强加值，当你在场景内首次因能量防御抵消了10点伤害值后，你使用此盾牌格挡时获得基于能量防御的【反伤2】（攻击你的目标会承受2点不可避免的纯能量伤害，这些伤害虽然无法被防御抵消，但可以被伤害吸收/减免等能力正常减少），持续一场景。</p><p>背理盾-捷诺<br> 价格：B+2000<br> 分类：轻盾<br> 武器伤害：10L<br> 特性：【格挡15】<br> 体积：8<br> 专业：盾<br> 伤害类型：物理-钝击<br> 描述：圣骑士团团长使用的盾牌，既是其守护信念的具象化，亦是绝望世界里倔强的抗争之光，即使认清世界无法拯救的现实，却仍坚守最后防线，在永恒的泪水与啜泣之海中战斗。<br> “顺利讨伐邪神，确认地面状况。——形式毫无改观，天灾仍在继续，邪恶的军队依旧络绎不绝的产生。”<br> “作为圣骑士团团长，我威尔伯特的结论如下：邪神只是天灾的一种，自神明离去的那一刻起，这个世界便早已迎来终结。”——「被撕下的战局记录」<br> 效果：【呜咽之海】：对于持盾者而言，美好的梦境与苦痛的现实皆为泡影，就连如同噩梦般的苦难，都无法侵袭持盾者本身。本武器的名称变更为【背理盾-捷诺】，当你使用此盾牌进行格挡时，你获得基于能量防御的【适应】并且免疫击落武器。因此格挡产生的【格挡防御】替换为【能量防御】。<br> 【守护与牺牲】：盾中的圣辉纹章承载着艾克列尔圣骑士团以血践行守护誓约的信仰，前人未消散的守护信仰与牺牲意志会化作炽热的圣能涌入盾牌守护活在当下的人，即使苦难永无止境。当你在场景内首次因能量防御抵消了5点伤害值后，此盾牌立刻获得额外的【格挡11】特性，并且使用本盾牌攻击时，额外获得1点增强加值，当你在场景内首次因能量防御抵消了10点伤害值后，你使用此盾牌格挡时获得基于能量防御的【反伤6】（攻击你的目标会承受6点不可避免的纯能量伤害，这些伤害虽然无法被防御抵消，但可以被伤害吸收/减免等能力正常减少），持续一场景。</p><p>艾克列尔圣辉盾下属技艺<br> 本技艺为差价升级，高等级替换低等级效果。本技艺等级不能高于本资源武器等级。</p><p>抗争绝望之人<br> D+750<br> 描述：为了在这个神明已经消失的世界活下去，我们必须努力。<br> 效果：神明消失的灾难虽然对你的身体造成了不可避免的摧残，但也让你学会了在末日生存下来的技巧，你的也内心不会再因为困境动摇。你的敏感范围减少10m。你获得基于能量防御的【防能量】特性，并且免疫B级读心效果与D级影响心灵来源的负面效果。</p><p>跨越试炼之人<br> B+2500<br> 描述：知晓了至上的安稳（但世界已无法拯救），接触了根源的欲求（无法放下已然逝去的众人）。<br> 英雄（凡人）认为己身没有资格拥有安稳，因而破除梦境。<br> ——克服安息的试炼。为了无法实现的愿望与祈祷，将（虚假的）希望带给尚且还活在当下的人民。<br> “我不允许此身拥有任何幸福，绝不允许。”<br> 效果：在购买本技艺后，你仍然视为拥有本技艺的D级效果但不具有【防能量】特性，当你首次因意志检定失败受到心灵来源的负面效果或因心灵来源的异常点数进入严重或毁灭状态时，你失去D级效果并永久替换为以下效果。<br> 【守护希望之人】：你无法原谅辜负了圣骑士团与民众期望的自己，再完成赎罪之前，你不会允许自己拥有任何安宁。你现在免疫A级读心效果与A级影响心灵来源的负面效果。<br> 【跨越试炼之人】：跨过试炼的你接受了安息带来的福音。你恢复因本技艺减少的敏感范围。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
